{"type":"permission_response","request_id":"perm-1773197225744-8f5siky","subtype":"success","response":{"updated_input":{"file_path":"/home/ketan/project/kapow/.claude/worktrees/worktree/contract-schemas/contracts/examples/technical-contract.example.json","content":"{
